(function () {
  'use strict';

  tinymce.PluginManager.add('customblocks', function (editor) {

    const wrap = function (className) {
      const selected = editor.selection.getContent({ format: 'html' });

      if (!selected) {
        editor.windowManager.alert('Выдели текст');
        return;
      }

      editor.selection.setContent(
        '<div class="' + className + '">' + selected + '</div>'
      );
    };
    
    /****** для добавления класса списку *******/
    const addChecklistToUl = function () {
    const node = editor.selection.getNode();
    const ul = editor.dom.getParent(node, 'ul');
    
    if (!ul) {
        editor.windowManager.alert('Курсор должен быть внутри списка (ul)');
        return;
    }
    
    editor.dom.toggleClass(ul, 'checklist');
    };

    /****** END для добавления класса списку *******/

    editor.ui.registry.addMenuButton('customblocks', {
      text: 'Blocks',
      fetch: function (callback) {
        callback([
          {
            type: 'menuitem',
            text: 'div.H2',
            onAction: function () {
              wrap('h2');
            }
          },{
            type: 'menuitem',
            text: 'div.H3',
            onAction: function () {
              wrap('h3');
            }
          },
          {
            type: 'menuitem',
            text: 'Highlight Box',
            onAction: function () {
              wrap('highlight-box');
            }
          },
          {
            type: 'menuitem',
            text: 'Warning Box',
            onAction: function () {
              wrap('warning-box');
            }
          },
          {
            type: 'menuitem',
            text: 'Success Box',
            onAction: function () {
              wrap('success-box');
            }
          },
            {
              type: 'menuitem',
              text: 'UL → checklist',
              onAction: function () {
                addChecklistToUl();
              }
            }

        ]);
      }
    });

  });

})();
